function calculateRisk(inputs) {
    const {
        airTemperature,
        windSpeed,
        exposureDuration,
        age,
        medicalConditions,
        activityLevel,
        clothingLayers,
        clothingQuality,
        hydrationStatus,
        acclimatization
    } = inputs;

    let totalScore = 0;

    // --- 1. Environmental Risk (BER) ---
    // Wind Chill Temperature (WCT) calculation (metric: °C, km/h)
    // Formula: WCT = 13.12 + 0.6215*T - 11.37*V^0.16 + 0.3965*T*V^0.16
    // Where T = airTemperature, V = windSpeed
    // Edge case: if windSpeed is 0 or very low, WCT approximates airTemperature
    let WCT;
    if (windSpeed <= 1) { 
        WCT = airTemperature;
    } else {
        WCT = 13.12 + (0.6215 * airTemperature) - (11.37 * Math.pow(windSpeed, 0.16)) + (0.3965 * airTemperature * Math.pow(windSpeed, 0.16));
    }

    let berScore = 0;
    if (WCT > 0) berScore = 0;
    else if (WCT > -5) berScore = 5; 
    else if (WCT > -10) berScore = 10; 
    else if (WCT > -20) berScore = 20; 
    else if (WCT > -30) berScore = 35; 
    else berScore = 50; 

    // Exposure Duration Factor (EDF)
    let edfFactor = 1;
    if (exposureDuration > 4) edfFactor = 2.0;
    else if (exposureDuration > 2) edfFactor = 1.5;
    else if (exposureDuration > 1) edfFactor = 1.2;

    totalScore += berScore * edfFactor;

    // --- 2. Personal Vulnerability Factor (PVF) ---
    let pvfScore = 0;

    // Age
    if (age < 5 || age > 75) pvfScore += 15;
    else if (age >= 65) pvfScore += 10; 
    else if ((age >= 5 && age <= 15) || (age >= 50 && age < 65)) pvfScore += 5; 

    // Medical Conditions
    switch (medicalConditions.toLowerCase().trim()) {
        case 'mild-cardiovascular-respiratory': pvfScore += 5; break;
        case 'diabetes-thyroid': pvfScore += 10; break;
        case 'severe-cardiovascular-respiratory': pvfScore += 15; break;
        case 'neurological-impaired-circulation': pvfScore += 20; break;
        case 'none': 
        default: break;
    }

    // Hydration Status
    switch (hydrationStatus.toLowerCase().trim()) {
        case 'mildly-dehydrated': pvfScore += 5; break;
        case 'significantly-dehydrated': pvfScore += 15; break;
        case 'well-hydrated': 
        default: break;
    }

    // Acclimatization
    switch (acclimatization.toLowerCase().trim()) {
        case 'well-acclimatized': pvfScore -= 5; break; 
        case 'not-acclimatized': pvfScore += 10; break;
        case 'partially-acclimatized': 
        default: break;
    }
    totalScore += pvfScore;

    // --- 3. Protective Measures Mitigation (PMM) ---
    let pmmScore = 0; 

    // Activity Level
    switch (activityLevel.toLowerCase().trim()) {
        case 'vigorous': pmmScore -= 20; break;
        case 'moderate': pmmScore -= 10; break;
        case 'light': pmmScore -= 5; break;
        case 'sedentary': 
        default: break;
    }

    // Clothing Layers (beyond 1 base layer, additional insulating layers)
    if (clothingLayers >= 4) pmmScore -= 15;
    else if (clothingLayers === 3) pmmScore -= 10;
    else if (clothingLayers === 2) pmmScore -= 5;

    // Outer Layer Quality
    switch (clothingQuality.toLowerCase().trim()) {
        case 'excellent': pmmScore -= 15; break;
        case 'good': pmmScore -= 10; break;
        case 'moderate': pmmScore -= 5; break;
        case 'poor': 
        default: break;
    }
    totalScore += pmmScore; 

    // --- Final Score Capping and Categorization ---
    let coldExposureRiskScore = Math.max(0, Math.min(100, Math.round(totalScore)));

    let riskCategory;
    if (coldExposureRiskScore <= 20) {
        riskCategory = "Low Risk";
    } else if (coldExposureRiskScore <= 40) {
        riskCategory = "Moderate Risk";
    } else if (coldExposureRiskScore <= 60) {
        riskCategory = "High Risk";
    } else if (coldExposureRiskScore <= 80) {
        riskCategory = "Very High Risk";
    } else {
        riskCategory = "Extreme Risk";
    }

    return {
        riskScore: coldExposureRiskScore,
        riskCategory: riskCategory,
    };
}
